                    <IconChevronRight className="size-3.5" />
                  )}
                  Channels
                </button>
              </SidebarGroupLabel>
              {openSections.channels && (
                <SidebarGroupContent>
                  <SidebarMenu>
                    {channels.map((channel) => (
                      <SidebarMenuItem key={channel}>
                        <SidebarMenuButton
                          isActive={selectedChannel === channel}
