                      <IconChevronRight className="size-3.5" />
                    )}
                    Machines &amp; Agents
                  </button>
                </SidebarGroupLabel>
                <DropdownMenu>
                  <DropdownMenuTrigger asChild>
                    <SidebarGroupAction title="Add">
                      <IconPlus className="size-3.5" />
