                          <span className="flex-1 truncate">{userName}</span>
                          <span className="text-xs text-muted-foreground shrink-0">you</span>
                        </SidebarMenuButton>
                      </SidebarMenuItem>
                    </SidebarMenu>
                  </SidebarGroupContent>
                )}
              </SidebarGroup>
            </>
